module d_flip_flop(
    input       d     ,
    input       clk   ,
    input       reset ,

    output reg  q
);
  wire _tap_d = d & {1{1'b1}};


   // D Flip-Flop with asynchronous reset
   always @(posedge clk or posedge reset) begin
       if (reset) begin
           q <= 1'b0;
       end else begin
           q <= d;
       end
   end

endmodule
